129:     /** The serializer used to write the TimeWindow type. */
130:     public static class Serializer extends TypeSerializerSingleton<TimeWindow> {
131:         private static final long serialVersionUID = 1L;
132: 
133:         @Override
134:         public boolean isImmutableType() {
135:             return true;
136:         }
137: 
138:         @Override
139:         public TimeWindow createInstance() {
140:             return new TimeWindow(0L, 1L);
141:         }
142: 
143:         @Override
144:         public TimeWindow copy(TimeWindow from) {
145:             return from;
146:         }
147: 
148:         @Override
149:         public TimeWindow copy(TimeWindow from, TimeWindow reuse) {
150:             return from;
151:         }
152: 
153:         @Override
154:         public int getLength() {
155:             return Long.BYTES + Long.BYTES;
156:         }
157: 
158:         @Override
159:         public void serialize(TimeWindow record, DataOutputView target) throws IOException {
160:             target.writeLong(record.start);
161:             target.writeLong(record.end);
162:         }
163: 
164:         @Override
165:         public TimeWindow deserialize(DataInputView source) throws IOException {
166:             long start = source.readLong();
167:             long end = source.readLong();
168:             return new TimeWindow(start, end);
169:         }
170: 
171:         @Override
172:         public TimeWindow deserialize(TimeWindow reuse, DataInputView source) throws IOException {
173:             return deserialize(source);
174:         }
175: 
176:         @Override
177:         public void copy(DataInputView source, DataOutputView target) throws IOException {
178:             target.writeLong(source.readLong());
179:             target.writeLong(source.readLong());
180:         }
181: 
182:         // ------------------------------------------------------------------------
183: 
184:         @Override
185:         public TypeSerializerSnapshot<TimeWindow> snapshotConfiguration() {
186:             return new TimeWindowSerializerSnapshot();
187:         }
